// Calculate heuristic risk predictions per entity for 30/60/90 day horizons
const entities = $input.all().map(item => item.json);
const now = new Date();

const predictions = [];

for (const entity of entities) {
  if (!entity.document || !entity.document.fields) continue;

  const fields = entity.document.fields;
  const entityId = entity.document.name.split('/').pop();
  const entityName = fields.name?.stringValue || fields.entity_name?.stringValue || entityId;
  const currentScore = parseInt(fields.compliance_score?.integerValue || fields.risk_score?.integerValue || 75);

  // Parse document expiration data
  const docsExpiring30 = parseInt(fields.docs_expiring_30?.integerValue || 0);
  const docsExpiring60 = parseInt(fields.docs_expiring_60?.integerValue || 0);
  const docsExpiring90 = parseInt(fields.docs_expiring_90?.integerValue || 0);
  const totalDocs = parseInt(fields.total_documents?.integerValue || 1);
  const expiredDocs = parseInt(fields.expired_documents?.integerValue || 0);

  // Historical trend (simple linear projection)
  const previousScore = parseInt(fields.previous_score?.integerValue || currentScore);
  const scoreTrend = currentScore - previousScore; // positive = improving

  // Heuristic prediction: factor in expirations and trends
  const predict = (days, expiringCount) => {
    // Base: current score with trend projection
    let predicted = currentScore + (scoreTrend * (days / 30));

    // Penalty for documents that will expire
    const expirationPenalty = totalDocs > 0 ? (expiringCount / totalDocs) * 25 : 0;
    predicted -= expirationPenalty;

    // Penalty for already expired documents
    const expiredPenalty = totalDocs > 0 ? (expiredDocs / totalDocs) * 15 : 0;
    predicted -= expiredPenalty;

    // Clamp to 0-100
    return Math.max(0, Math.min(100, Math.round(predicted)));
  };

  const score30 = predict(30, docsExpiring30);
  const score60 = predict(60, docsExpiring30 + docsExpiring60);
  const score90 = predict(90, docsExpiring30 + docsExpiring60 + docsExpiring90);

  predictions.push({
    entity_id: entityId,
    entity_name: entityName,
    current_score: currentScore,
    predicted_score_30d: score30,
    predicted_score_60d: score60,
    predicted_score_90d: score90,
    score_trend: scoreTrend,
    docs_at_risk: docsExpiring30 + docsExpiring60 + docsExpiring90,
    max_drop_predicted: currentScore - Math.min(score30, score60, score90),
    risk_increasing: score90 < currentScore
  });
}

// Sort by most at risk (largest predicted score drop)
predictions.sort((a, b) => b.max_drop_predicted - a.max_drop_predicted);

return [{
  json: {
    predictions: predictions,
    entity_count: predictions.length,
    at_risk_count: predictions.filter(p => p.risk_increasing).length,
    critical_entities: predictions.filter(p => p.max_drop_predicted >= 20),
    predicted_at: new Date().toISOString()
  }
}];

